<script setup>
import {reactive,ref} from 'vue';import {useRouter} from 'vue-router';import {useAuthStore} from '../stores/auth'
const auth=useAuthStore(),router=useRouter(),loading=ref(false),error=ref(''),form=reactive({username:'',name:'',email:'',phone:'',password:'',confirmPassword:''})
async function submit(){error.value='';if(form.password.length<8)return error.value='密碼至少需要 8 個字元。';if(form.password!==form.confirmPassword)return error.value='密碼與確認密碼不一致。';loading.value=true;try{const {confirmPassword,...payload}=form;await auth.register(payload);router.replace('/member/profile')}catch(e){error.value=e.message}finally{loading.value=false}}
</script>
<template><section class="auth-card card"><p class="eyebrow">CREATE ACCOUNT</p><h1>建立會員帳號</h1><p>完成註冊後即可使用會員中心與後續平台服務。</p><p v-if="error" class="alert error">{{error}}</p><form @submit.prevent="submit"><label>使用者名稱<input v-model.trim="form.username" maxlength="50" required autocomplete="username"></label><label>姓名<input v-model.trim="form.name" maxlength="100" required autocomplete="name"></label><label>電子信箱<input v-model.trim="form.email" type="email" maxlength="100" required autocomplete="email"></label><label>手機<input v-model.trim="form.phone" maxlength="20" autocomplete="tel"></label><label>密碼<input v-model="form.password" type="password" minlength="8" maxlength="72" required autocomplete="new-password"><small>至少 8 個字元。</small></label><label>確認密碼<input v-model="form.confirmPassword" type="password" required autocomplete="new-password"></label><button class="button button-primary button-full" :disabled="loading">{{loading?'註冊中…':'註冊並登入'}}</button></form><p>已有帳號？ <RouterLink class="text-link" to="/login">返回登入</RouterLink></p></section></template>
